head.script:
/**
 * 화 면 명 : 인허가 취득내역 조회
 * 메뉴경로 : 공통/총무업무/인허가 관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/permitmgnt/zz_950_01_02b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-12-04
 * 수정이력  :
 *    - 2025-12-04      정승혜    최초작성
 * 메모 :
 * 그리드 mergeCells="byrestriccol" 하면 첨부파일명이 병합되어버려서 컬럼 개별적으로 colMerge="true" upperColumn="chgDesc" 부여
 * 조회조건 : 
 * 자식페이지 zz_950_01_01b / url 수정해야함
 * 
 */

scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.vFirstDate = new Date().before(0, 0, 7).format("YYYYMMDD");

scwin.memJson = $c.data.getMemInfo();
scwin.empNo = scwin.memJson.empNo;
scwin.coCd = scwin.memJson.coCd;
scwin.coClsCd = scwin.memJson.coClsCd;
scwin.userHomeClsCd = scwin.memJson.userHomeClsCd;

scwin.params = "";
scwin.cstmrId = "";
scwin.salesInfoId = "";

scwin.privAdmin = scwin.memJson.privAdmin; // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

scwin.gv_CurDate = scwin.vCurDate;
scwin.gv_FirstDate = scwin.vFirstDate;
scwin.vLoginCoCd =$c.gus.cfIsNull(scwin.coCd)?'':scwin.coCd; // 소속 자회사  
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.coClsCd)?'': scwin.coClsCd  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd= scwin.userHomeClsCd;        // 사용자소속구분코드 
scwin.isSubCompany = false;  

//hidden
scwin.txtCoClsCd = "";

scwin.isStarted = true; // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    if(scwin.params["cstmrId"] == null){scwin.cstmrId = "";}else{scwin.cstmrId = scwin.params["cstmrId"]}
    if(scwin.params["salesInfoId"] == null){scwin.salesInfoId = "";}else{scwin.salesInfoId = scwin.params["salesInfoId"]}

    // getCodeList
    const codeOptions = [
        { grpCd : "ZZ590", compID : "lc_apprTypeCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    $c.gus.cf_AllowCharLength(ed_apprCd); 

    scwin.f_createHeader();
};

// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function() {
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// function name : f_createHeader
// function desc : Grid Header정보 Setting
//-------------------------------------------------------------------------
scwin.f_createHeader = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

scwin.f_createHistoryHeader = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if(scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD){
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF) {
    udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc2
                            ,ed_coCd.getValue(), ed_coNm.getValue()
                            ,pWinCloseTF,null,null,null,null
                            ,null,null,null,null,null
        );
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc2 = function(rtnList) {
    if(rtnList != null ) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        scwin.txtCoClsCd = rtnList[1];
    }else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    }else{
        scwin.isSubCompany = false;
    }

    if ( scwin.isStarted == true )  // 최초 이벤트 여부 (자회사 여부를 최초 한번만 실행-팝업 리턴 시간차)
    {
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        if ("T" == scwin.privAdmin || !scwin.isSubCompany) {  
            $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company]);
        }else{
            $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);
        }
        scwin.isStarted = false;
    }

};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
    $c.sbm.execute(sbm_tr_retrieve);
};

scwin.f_Retrieve2 = function() {
    $c.sbm.execute(sbm_tr_retrieveHis);
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(portCondtionPart);
};

//-------------------------------------------------------------------------
// function name : f_openPopUp
// function desc : popup
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let condition = "";

    switch (disGubun)
    {
        case 1: // 관리부서
            condition = "";
            udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc
                        ,pCode					// 화면에서의 ??? Code Element의	Value
                        ,pName					// 화면에서의 ??? Name Element의	Value
                        ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                        ,null					// Title순서
                        ,'150,170'  		    // 보여주는 각 컬럼들의 폭
                        ,null					// 컬럼중에서 숨기는	컬럼 지정
                        ,condition					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                        ,null					// 윈도우 위치 Y좌표
                        ,null					// 윈도우 위치 X좌표
                        ,null					// 중복체크여부	("F")
                        ,pAllSearch				// 전체검색허용여부	("F")
                        ,null			    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        break;
        case 3: // 담당자
            condition = "";
            udc_loBranEmpInfo.cfCommonPopUp(scwin.udc_loBranEmpInfo_callBackFunc
                        ,pCode                  // 화면에서의 ??? Code Element의  Value
                        ,pName                  // 화면에서의 ??? Name Element의  Value
                        ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                        ,'5'                    // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                        ,null                   // Title순서
                        ,'150,170'              // 보여주는 각 컬럼들의 폭
                        ,null                   // 컬럼중에서 숨기는    컬럼 지정
                        ,condition                  // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                        ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                        ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이
                        ,null                   // 윈도우 위치 Y좌표
                        ,null                   // 윈도우 위치 X좌표
                        ,null                   // 중복체크여부   ("F")
                        ,pAllSearch             // 전체검색허용여부 ("F")
                        ,null               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        break;
        case 4: // 회사구분
            udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc
                        ,pCode                  // 화면에서의 ??? Code Element의  Value
                        ,pName                  // 화면에서의 ??? Name Element의  Value
                        ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                        ,null
                        ,null
                        ,null
                        ,null
                        ,null
                        ,null
                        ,null
                        ,null
                        ,null
            );
        break;

    default:
  	break;        
    }

};

